PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT (YEAR(?date) AS ?year) WHERE {
  ?event wdt:P750 wd:Q38205;
         wdt:P585 ?date.
  FILTER (MONTH(?date) = 4)
  FILTER (DAY(?date) = 1)
} ORDER BY DESC(?year) LIMIT 1

